import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-candidate-dashboard',
  template: `
  <div style="padding:30px;font-family:Arial">
    <div style="display:flex;justify-content:space-between;align-items:center">
      <div>
        <h1>Candidate Dashboard</h1>
        <p style="color:gray;margin:0">{{auth.user?.email}}</p>
      </div>
      <button (click)="logout()" style="padding:8px 16px;background:black;color:white;border:none;border-radius:6px;cursor:pointer">Logout</button>
    </div>

    <h2>Available Internships</h2>
    <div *ngFor="let i of internships" [ngStyle]="card">
      <h3 style="text-align:center;color:#111827">{{i.companyName}}</h3>
      <p><b>Role:</b>{{i.title}}</p>
      <p><b>Location:</b> {{i.workLocation}}</p>
      <p><b>CTC:</b> {{i.ctc}}</p>
      <p><b>Description:</b> {{i.description}}</p>
      <button *ngIf="hasApplied(i.id); else canApply" disabled style="padding:6px 12px;background:#e5e7eb;color:#374151;border:none;border-radius:6px">Applied</button>
      <ng-template #canApply><button (click)="selectInternship(i)" style="padding:6px 12px;background:#111827;color:white;border:none;border-radius:6px">Apply</button></ng-template>
    </div>

    <div *ngIf="selectedInternship" [ngStyle]="formBox">
      <h2>Apply for {{selectedInternship.title}}</h2>
      <input placeholder="Full Name" [(ngModel)]="candidateName" [ngStyle]="input" />
      <input placeholder="Phone" [(ngModel)]="phone" [ngStyle]="input" />
      <input placeholder="Degree" [(ngModel)]="degree" [ngStyle]="input" />
      <input placeholder="College" [(ngModel)]="college" [ngStyle]="input" />
      <input placeholder="CGPA" [(ngModel)]="cgpa" [ngStyle]="input" />
      <input placeholder="Skills" [(ngModel)]="skills" [ngStyle]="input" />
      <input type="file" accept="application/pdf" (change)="onResumeSelected($event)" />
      <button (click)="handleApply()" style="margin-top:15px;padding:10px 20px;background:#111827;color:white;border:none;border-radius:6px;cursor:pointer">Submit Application</button>
    </div>

    <h2 style="margin-top:40px">My Applications</h2>
    <div *ngFor="let app of applications" [ngStyle]="card">
      <h3 style="text-align:center;color:#111827">{{ getInternship(app)?.companyName }}</h3>
      <h3>{{ getInternship(app)?.title }}</h3>

      <div *ngIf="app.status === 'TEST_ACTIVE'">
        <p>Test active till {{ formatDate(app.testDate) }}</p>
        <button (click)="router.navigate(['/candidate/test', app.id])" style="padding:8px 15px;background:#111827;color:#fff;border:none;border-radius:6px;margin-top:10px">Take Test</button>
      </div>

      <div *ngIf="app.status === 'TEST_PASSED'"> <p style="color:#111827">Online Test-Passed</p> </div>
      <div *ngIf="app.status === 'TEST_FAILED'"> <p style="color:red;font-weight:bold">Online Test-Not Cleared</p> </div>

      <div *ngIf="app.offerLetterFile && app.offerStatus !== 'REJECTED'">
        <a [href]="'http://localhost:8080/offers/' + app.offerLetterFile" target="_blank">Download Offer Letter</a>

        <div *ngIf="app.offerStatus === 'PENDING'">
          <button (click)="updateOfferStatus(app.id, 'ACCEPTED')">Accept</button>
          <button (click)="updateOfferStatus(app.id, 'REJECTED')">Reject</button>
        </div>

        <div *ngIf="app.offerStatus === 'ACCEPTED' && !app.signedOfferLetter">
          <input type="file" (change)="onSignedOfferSelected(app.id, $event)" />
          <button (click)="uploadSignedOffer(app.id)">Upload Signed Offer</button>
        </div>

        <div *ngIf="app.signedOfferLetter">
          <ng-container *ngIf="employee">
            <div style="margin-top:15px;padding:15px;border:1px solid white;border-radius:8px;background:white">
              <h3 style="color:#16a34a"> Welcome to the Company</h3>
              <p><b>Employee ID:</b> {{employee.employeeId}}</p>
              <p><b>Date of Joining:</b> {{employee.dateOfJoining}}</p>
              <p><b>Reporting Time:</b> {{employee.reportingTime}}</p>
              <p><b>Location:</b> {{employee.workLocation}}</p>
              <p><b>Manager:</b> {{employee.managerName}}</p>
              <p><b>Manager Email:</b> {{employee.managerEmail}}</p>
              <p><b>Manager Contact:</b> {{employee.managerContact}}</p>
            </div>
          </ng-container>

          <ng-container *ngIf="!employee">
            <p style="color:black">Offer Process-Completed</p>
            <button *ngIf="onboardingStatus===null || onboardingStatus==='REJECTED'" (click)="router.navigate(['/onboarding'], { state: { applicationId: app.id } })" style="margin-top:10px;padding:8px 14px;background:#111827;color:white;border:none;border-radius:6px;cursor:pointer">Fill Onboarding Form</button>
            <p *ngIf="onboardingStatus==='PENDING'" style="color:orange;margin-top:10px">Onboarding submitted – waiting for HR verification</p>
            <p *ngIf="onboardingStatus==='VERIFIED'" style="color:green;margin-top:10px">Onboarding verified</p>
            <p *ngIf="onboardingStatus==='REJECTED'" style="color:red;margin-top:10px">Onboarding rejected</p>
          </ng-container>
        </div>
      </div>
    </div>
  </div>
  `
})
export class CandidateDashboardComponent implements OnInit, OnDestroy {
  internships: any[] = [];
  applications: any[] = [];
  selectedInternship: any = null;
  candidateName = '';
  phone = '';
  degree = '';
  college = '';
  cgpa = '';
  skills = '';
  resume: any = null;
  signedFiles: any = {};
  onboardingStatus: any = null;
  latestSignedOfferId: any = null;
  employee: any = null;

  private intervalId: any;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    if (!this.auth.user?.email) return;
    this.fetchInternships();
    this.fetchApplications();
    this.fetchEmployee();
    this.intervalId = setInterval(() => { this.fetchApplications(); this.fetchOnboarding(); }, 5000);
  }

  ngOnDestroy() { clearInterval(this.intervalId); }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  async fetchOnboarding() {
    if (!this.latestSignedOfferId) { this.onboardingStatus = null; return; }
    try {
      const res: any = await this.http.get(`http://localhost:8080/api/onboarding/application/${this.latestSignedOfferId}`).toPromise();
      this.onboardingStatus = res.length > 0 ? res[res.length - 1].status : null;
    } catch (err) { console.error(err); this.onboardingStatus = null; }
  }

  async fetchEmployee() {
    if (!this.auth.user?.email) return;
    try { this.employee = await this.http.get(`http://localhost:8080/api/employees/${this.auth.user.email}`).toPromise(); } catch (err) { this.employee = null; }
  }

  async fetchInternships() { try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) { console.error(err); } }

  async fetchApplications() { try {
      const res: any = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise();
      const filtered = res.filter((app: any) => app.email === this.auth.user?.email);
      this.applications = filtered;
      const signed = filtered.filter((app: any) => app.signedOfferLetter).slice(-1)[0];
      this.latestSignedOfferId = signed?.id || null;
      this.fetchOnboarding();
    } catch (err) { console.error(err); }
  }

  hasApplied(internshipId: any) { return this.applications.some(app => app.internshipId === internshipId); }

  selectInternship(i: any) { this.selectedInternship = i; }

  onResumeSelected(e: any) { this.resume = e.target.files?.[0]; }

  async handleApply() {
    if (!this.resume) return alert('Please upload resume');
    const form = new FormData();
    form.append('internshipId', this.selectedInternship.id);
    form.append('candidateName', this.candidateName);
    form.append('email', this.auth.user?.email || '');
    form.append('phone', this.phone);
    form.append('degree', this.degree);
    form.append('college', this.college);
    form.append('cgpa', this.cgpa);
    form.append('skills', this.skills);
    form.append('resume', this.resume);
    await this.http.post('http://localhost:8080/api/applications/apply', form).toPromise();
    alert('Application submitted!');
    this.selectedInternship = null; this.candidateName = this.phone = this.degree = this.college = this.cgpa = this.skills = ''; this.resume = null; this.fetchApplications();
  }

  getInternship(app: any) { return this.internships.find(i => i.id === app.internshipId); }

  formatDate(dateString: any) { if (!dateString) return ''; return new Date(dateString).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }); }

  updateOfferStatus(id: any, status: string) { this.http.post('http://localhost:8080/api/applications/offer-status', null, { params: { applicationId: id, status } as any }).toPromise().then(() => this.fetchApplications()); }

  onSignedOfferSelected(id: any, e: any) { this.signedFiles = { ...this.signedFiles, [id]: e.target.files?.[0] }; }

  async uploadSignedOffer(id: any) {
    const file = this.signedFiles[id]; if (!file) return alert('Upload signed offer');
    const form = new FormData(); form.append('applicationId', id); form.append('file', file);
    await this.http.post('http://localhost:8080/api/applications/upload-signed-offer', form).toPromise();
    alert('Signed offer uploaded'); this.signedFiles = { ...this.signedFiles, [id]: null }; this.fetchApplications();
  }

  // styles used by template
  card = { border: '1px solid #e5e7eb', padding: '20px', borderRadius: '10px', marginBottom: '20px', background: '#ffffff', color: '#111827' } as any;
  input = { width: '100%', marginBottom: '10px', padding: '10px', border: '1px solid #e5e7eb', borderRadius: '6px', color: '#111827' } as any;
  formBox = { marginTop: '30px', padding: '20px', background: '#ffffff', borderRadius: '10px', border: '1px solid #e5e7eb' } as any;
}
